#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

class Solution { public: bool recoverMaxHeap(std::vector<int>& nums, const std::vector<int>& indToDelete) { int i = 0; for (int idx : indToDelete) { nums[idx] = INT_MIN; } for (i = 0; i < nums.size(); i++) { if (nums[i] == INT_MIN) { continue; } int left = 2 * i + 1; int right = 2 * i + 2; if (left >= nums.size()) { continue; } if (right >= nums.size()) { maxHeapify(nums, i, left); continue; } if (nums[i] < nums[left] || nums[i] < nums[right]) { maxHeapify(nums, i, left); maxHeapify(nums, i, right); } } return true; }

private: void maxHeapify(std::vector<int>& nums, int i, int j) { if (nums[i] < nums[j]) { std::swap(nums[i], nums[j]); } while (i > 0 && nums[i] < nums[(i - 1) / 2]) { std::swap(nums[i], nums[(i - 1) / 2]); i = (i - 1) / 2; } }
};
int main() {
    Solution solution;
    std::vector<int> nums = {4, 3, 2, 1};
    std::vector<int> indToDelete = {0};
    cout << boolalpha << solution.recoverMaxHeap(nums, indToDelete) << endl;
    return 0;
}
